window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["w"]={"Wojciech": "<b>Wojciech</b>, <b>Wociech</b> – staropolskie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Wojciech w 2017 r. zajmował 9. miejsce w grupie imion męskich. W całej populacji Polaków Wojciech zajmował w 2017 r. 16. miejsce (317 857 nadań).", "Wiesław": "<b>Wiesław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Była to skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Wielis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wielisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Wielis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wielesław</a>. Mogło oznaczać „tego, kto pragnie sławy”. Według <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw_Kopali%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Władysława Kopalińskiego</a> jest to imię literackie utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Wincenty_Reklewski\" target=\"_blank\" rel=\"noopener noreferrer\">Wincentego Reklewskiego</a> pod koniec XVIII w. spopularyzowane przez poemat <i><a href=\"https://pl.wikipedia.org/wiki/Wies%C5%82aw_(sielanka)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiesław</a></i> <a href=\"https://pl.wikipedia.org/wiki/Kazimierz_Brodzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Kazimierza Brodzińskiego</a>, co nie jest prawdą w świetle nowszych analiz.", "Wiktor": "<b>Wiktor</b>, <b>Wiktoriusz</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>victor</em> – zwycięzca) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Władysław": "<b>Władysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię męskie pochodzenia słowiańskiego</a> złożone z dwu członów: <i>vlad-</i> („władać”) oraz <i>-slav</i> („sława”) i oznacza „ten, który włada sławą”, tj. „sławny, znamienity”.", "Waldemar": "<b>Waldemar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego etymologia nie jest pewna. Uważa się, że pochodzi ono z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> od słowa „wald” oznaczającego władcę oraz słowa „meri” – „sławnego”. Możliwe również, że jest zgermanizowaną formą <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a> Vladimir-a utworzonego z członów „vladi” oraz „mir” oznaczających kolejno: władzę oraz pokój.", "Witold": "<b>Witold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a> <i>Vytautas</i> (<i>vyti</i> „gnać” + <i>tauta</i> „lud”, co znaczy „władający ludem” lub „przewodzący ludowi”). Możliwe także, że jest to imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<i>witu</i> „las” + <i>waltan</i> „rządzić”, co oznacza „rządzący lasem”).", "Włodzimierz": "<b>Włodzimierz</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się ze słów <i>Włodzi-</i> – „panuje” i <i>-mierz</i>, które pochodzi z dawnego <i>-mir</i> – „pokój”. Formą staropolską tego imienia jest zatem <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimir\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzimir</a> (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a> czy <a href=\"https://pl.wikipedia.org/wiki/Krzesimir\" target=\"_blank\" rel=\"noopener noreferrer\">Krzesimir</a>).", "Wacław": "<b>Wacław</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czes.</a> <i>Václav</i>, niem. <i>Wenzel</i>) – ten, który zdobędzie więcej sławy, por. <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a>; <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Obecna forma w języku polskim jest czechizmem – po staropolsku brzmiałoby ono <i><b><a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesław</a></b></i>.", "Wincenty": "<b>Wincenty</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>vincens</em> – zwyciężający) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Walenty": "<b>Walenty</b>, <b>Walentyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, które wywodzi się od przydomka <i>Valentinus</i>, utworzonego od łac. <i>valens</i> – „mocny, silny, zdrowy”. Imię to było notowane w Polsce od XIII w. w formie <i>Valentinus</i>, natomiast w formie Walenty i Walentyn – od XV w. (zapis formy Walentyn jest o niemal 30 lat późniejszy niż formy Walenty).", "Wawrzyniec": "Imię wywodzi się od słowa <a href=\"https://pl.wikipedia.org/wiki/Wawrzyn_szlachetny\" target=\"_blank\" rel=\"noopener noreferrer\">wawrzyn</a>, które pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>laurus</em>.", "Wilhelm": "<b>Wilhelm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W starogermańskim oznaczało „tego, który udziela schronienia”. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Wilhelmina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wilhelmina</a> (zdrobnienie Mina). Imię szczególnie popularne w krajach anglosaskich.", "Walter": "<b>Walter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>waltan</i> i <i>heri</i> oznaczających „panować” i „lud”. Imię to było znane w średniowiecznej Polsce w formie Walcerz.", "Walerian": "<b>Walerian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „mocny”, „silny”, „zdrowy”. Wśród patronów – <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Walerian\" target=\"_blank\" rel=\"noopener noreferrer\">św. Walerian</a>, <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennik\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> z <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a> (wspominany 14 kwietnia).", "William": "<b>Wilhelm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W starogermańskim oznaczało „tego, który udziela schronienia”. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Wilhelmina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wilhelmina</a> (zdrobnienie Mina). Imię szczególnie popularne w krajach anglosaskich.", "Werner": "<b>Werner</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego.", "Wit": "<b>Wit</b> – imię męskie pochodzenia łacińskiego.", "Wolfgang": "<b>Wolfgang</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego.", "Walery": "<b>Walery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Powstało ono z przydomka <i>Valerius</i>, który pochodzi z nazwy rodu <i>Waleriuszów</i> i oznaczał pierwotnie „człowieka z rodu Waleriuszów”. Porównaj z: <a href=\"https://pl.wikipedia.org/wiki/Waleriusz\" target=\"_blank\" rel=\"noopener noreferrer\">Waleriusz</a>", "Wieńczysław": "<b>Wieńczysław</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone w czasach nowszych; jego zapisy pojawiają się dopiero w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>. Prawdopodobnie powstało przez analogię do imion staropolskich i miało oznaczać „ten, którego wieńczy sława”. Inną hipotezą jest powstanie tego imienia w wyniku specyficznego odczytania imienia <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesław</a>, być może za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">języków wschodniosłowiańskich</a> (<b>Wiaczesław</b>).", "Winicjusz": "<b>Winicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, które wywodzi się od słowa <i>vinum</i> – „wino”. Imię to zyskało względną popularność w Polsce dzięki <i><a href=\"https://pl.wikipedia.org/wiki/Quo_vadis\" target=\"_blank\" rel=\"noopener noreferrer\">Quo vadis</a></i> <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryka Sienkiewicza</a>.", "Wadim": "<b>Wadim</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bia%C5%82oruski\" target=\"_blank\" rel=\"noopener noreferrer\">biał</a>. Вадзім (Vadzim), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a> Вадим, Vadim (Вадим), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ukrai%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ukr.</a> Vadym (Вадим)</i>) – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_wschodni\" target=\"_blank\" rel=\"noopener noreferrer\">wschodniosłowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o nieznanej etymologii popularne w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a> i <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a>, ale też występujące np. we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>.", "Witalis": "<b>Witalis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „życiowy, zdolny do życia” (<i>vitalis</i>) i wyrażało życzenie rodziców, żeby dziecko się dobrze chowało. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Witalis_i_Agrykola\" target=\"_blank\" rel=\"noopener noreferrer\">św. Witalis</a>, męczennik, zm. ok. 300.", "Wiaczesław": "Pod wpływem języka czeskiego przyjęła się jego forma <a href=\"https://pl.wikipedia.org/wiki/Wac%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wacław</a>. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Wschodniosłowiańskim</a> odpowiednikiem tego imienia jest <i>Вячеслав</i> (Wiaczesław). Z kolei imię <a href=\"https://pl.wikipedia.org/wiki/Wie%C5%84czys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wieńczysław</a> mogło powstać w wyniku specyficznego odczytania imienia <i>Więcesław</i>.", "Witosław": "<b>Witosław</b>, <b>Witsław</b>, <b>Wicsław</b>, <b>Wicław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię męskie</a>, złożone z członów <i>Wit(o)-</i> („pan, władca”), i <i>-sław</i> („sława”). Mogło ono mieć charakter życzący i oznaczać „tego, który będzie sławnym panem”. Formą skróconą tego imienia był <a href=\"https://pl.wikipedia.org/wiki/Witosz\" target=\"_blank\" rel=\"noopener noreferrer\">Witosz</a> i <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wisław</a>, a żeńskimi odpowiednikami – odpowiednio <a href=\"https://pl.wikipedia.org/wiki/Witos%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Witosława</a> i <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wisława</a>. W XII wieku (1136), jako Witosz, pojawił się w <i><a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a></i>. Formami zdrobniałymi są Wit, Witek, Witko, Witaj, Witosz.", "Wenancjusz": "<b>Wenancjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>venans</i> – \"polujący\". Jego formą oboczną jest <a href=\"https://pl.wikipedia.org/wiki/Wenanty\" target=\"_blank\" rel=\"noopener noreferrer\">Wenanty</a>.", "Wirgiliusz": "<b>Wirgiliusz</b> (także <b>Wergiliusz</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od rzymskiego rodu <i>Virgilius</i> (pol. <i>Wirgiliusz</i>, <i>Wergiliusz</i>). Zazwyczaj wymienia się dwóch świętych o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Wirgiliusz_z_Salzburga\" target=\"_blank\" rel=\"noopener noreferrer\">biskupa Salzburga</a> i <a href=\"https://pl.wikipedia.org/wiki/Wirgiliusz_z_Arles\" target=\"_blank\" rel=\"noopener noreferrer\">biskupa z Arles</a>.", "Wenanty": "<b>Wenanty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>venans</i> – „polujący”. Jego formą oboczną jest <a href=\"https://pl.wikipedia.org/wiki/Wenancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Wenancjusz</a>.", "Wilibald": "<b>Wilibald</b> – imię męskie pochodzenia germańskiego. Pochodzi od słów <i>wille</i>, czyli chęć i <i>bald</i>, czyli moc.", "Wendelin": "<b>Wendelin</b>, <b>Wandalin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o nieustalonym do końca pochodzeniu, ale przyjmuje się, że stanowi ono skróconą formę imion germańskich dwuczłonowych, takich jak <i>Wendelbert</i>, <i>Wendelmar</i>, <i>Wendelgart</i>. Pierwszy człon, <i>Wendel-</i>, najprawdopodobniej oznaczał „pochodzący z plemienia <a href=\"https://pl.wikipedia.org/wiki/Wandalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Wandalów”</a>. Św. Wendelin był pasterzem i być może mnichem, według tradycji przybyłym z <a href=\"https://pl.wikipedia.org/wiki/Irlandia\" target=\"_blank\" rel=\"noopener noreferrer\">Irlandii</a>.", "Willy": "<b>Andrzej Włast</b>, właściwie <b>Gustaw Baumritter</b>, <a href=\"https://pl.wikipedia.org/wiki/Pseudonim\" target=\"_blank\" rel=\"noopener noreferrer\">ps. art.</a> <b>Willy </b>(ur. <a href=\"https://pl.wikipedia.org/wiki/17_marca\" target=\"_blank\" rel=\"noopener noreferrer\">17 marca</a> <a href=\"https://pl.wikipedia.org/wiki/1895\" target=\"_blank\" rel=\"noopener noreferrer\">1895</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%81%C3%B3d%C5%BA\" target=\"_blank\" rel=\"noopener noreferrer\">Łodzi</a>, zm. w <a href=\"https://pl.wikipedia.org/wiki/1942\" target=\"_blank\" rel=\"noopener noreferrer\">1942</a> lub <a href=\"https://pl.wikipedia.org/wiki/1943\" target=\"_blank\" rel=\"noopener noreferrer\">1943</a> w <a href=\"https://pl.wikipedia.org/wiki/Warszawa\" target=\"_blank\" rel=\"noopener noreferrer\">Warszawie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> poeta pochodzenia żydowskiego, librecista. Był autorem najbardziej popularnych tekstów polskich piosenek dwudziestolecia międzywojennego. Współtwórca fenomenu polskiego tanga i piosenek przedmieść miasta.", "Walentyn": "<b>Walenty</b>, <b>Walentyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, które wywodzi się od przydomka <i>Valentinus</i>, utworzonego od łac. <i>valens</i> – „mocny, silny, zdrowy”. Imię to było notowane w Polsce od XIII w. w formie <i>Valentinus</i>, natomiast w formie Walenty i Walentyn – od XV w. (zapis formy Walentyn jest o niemal 30 lat późniejszy niż formy Walenty).", "Włodzisław": "<b>Włodzisław</b>, <b>Włocsław</b>, <b>Włocław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Włodzi-</i> („władać, panować”) i <i>-sław</i>. W późniejszym czasie pod wpływem języka czeskiego powstała z tego imienia obecnie bardziej znana forma, <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię to (Władzisław? — <i>Ladislaw</i>) zanotowano u około 1000 osób.", "Wirginiusz": "<b>Wirginiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzi od nazwy rzymskiego rodu <i>Wirginiuszów</i>.", "Wielisław": "<b>Wielisław</b>, <b>Wielesław</b>, <b>Wielsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Składa się z członów: <i>Wiele-</i> („chcieć, kazać, radzić”) i <i>-sław</i> („sława”). Mogło oznaczać „tego, kto pragnie sławy”. Skróconą formą tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Wies%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wiesław</a>.", "Wojmir": "<b>Wojmir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Woj-</i> (\"wojownik\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać kogoś, kto wojując zaprowadza spokój i dobro. W niektórych przypadkach imię to mogło utożsamiać się brzmieniowo z jedną z form imienia <a href=\"https://pl.wikipedia.org/wiki/Wolimir\" target=\"_blank\" rel=\"noopener noreferrer\">Wolimir</a>.", "Wilfred": "<b>Wilfryd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z elementów <i>wil</i> - \"wola, pragnienie\" i <i>fred</i> - \"pokój\". Znaczeniowo można je porównać ze słowiańskim imieniem <a href=\"https://pl.wikipedia.org/wiki/Wolimir\" target=\"_blank\" rel=\"noopener noreferrer\">Wolimir</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Wilfryd_z_Yorku\" target=\"_blank\" rel=\"noopener noreferrer\">Wilfryd z Yorku</a>, zm. w <a href=\"https://pl.wikipedia.org/wiki/709\" target=\"_blank\" rel=\"noopener noreferrer\">709</a> roku.", "Wojsław": "<b>Wojsław</b>, <b>Wojesław</b>, <b>Wojisław</b>, <b>Wosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Woj-</i> („wojownik”) i <i>-sław</i> („sława”). Oznacza „tego, który zdobywa sławę w wojnach”, „sławnego wojownika”. Imię to mogło przybierać także formę <a href=\"https://pl.wikipedia.org/wiki/Wys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wysław</a>. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Wojs%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wojsława</a>.", "Witosz": "<b>Witosław</b>, <b>Witsław</b>, <b>Wicsław</b>, <b>Wicław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię męskie</a>, złożone z członów <i>Wit(o)-</i> („pan, władca”), i <i>-sław</i> („sława”). Mogło ono mieć charakter życzący i oznaczać „tego, który będzie sławnym panem”. Formą skróconą tego imienia był <a href=\"https://pl.wikipedia.org/wiki/Witosz\" target=\"_blank\" rel=\"noopener noreferrer\">Witosz</a> i <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wisław</a>, a żeńskimi odpowiednikami – odpowiednio <a href=\"https://pl.wikipedia.org/wiki/Witos%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Witosława</a> i <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wisława</a>. W XII wieku (1136), jako Witosz, pojawił się w <i><a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a></i>. Formami zdrobniałymi są Wit, Witek, Witko, Witaj, Witosz.", "Warcisław": "<b>Warcisław</b>, <b>Warcsław</b>, <b>Warsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Składa się z członu <i>Wroci-</i> („wrócić, wrócić się, przywrócić”) w formie <i>Warci-</i> i <i>-sław</i> („sława”). Może zatem oznaczać „ten, który przywróci sławę”. Od skróconej formy tego imienia, <i><b>Warsz</b></i>, w formie dzierżawczej, pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Warszawa\" target=\"_blank\" rel=\"noopener noreferrer\">Warszawa</a>, dawniej <b>Warszewa</b>.", "Wiktorian": "<b>Wiktorian</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> utworzony poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>–ianus</i> do imienia <a href=\"https://pl.wikipedia.org/wiki/Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktor</a>. Żeński odpowiednik tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Wiktoriana\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoriana</a>, jest notowana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a>.", "Wiktoryn": "<b>Wiktoryn</b> – imię męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktor</a>, utworzone za pomocą przyrostka oznaczającego przynależność lub pochodzenie.", "Wilkomir": "<b>Wilkomir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Wilko-</i> (\"wilk\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać tego, który zapewnia pokój od wilków. Do form pochodnych (zdrobniałych) tego imienia należy m.in. Wilczan.", "Wilfryd": "<b>Wilfryd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z elementów <i>wil</i> - \"wola, pragnienie\" i <i>fred</i> - \"pokój\". Znaczeniowo można je porównać ze słowiańskim imieniem <a href=\"https://pl.wikipedia.org/wiki/Wolimir\" target=\"_blank\" rel=\"noopener noreferrer\">Wolimir</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Wilfryd_z_Yorku\" target=\"_blank\" rel=\"noopener noreferrer\">Wilfryd z Yorku</a>, zm. w <a href=\"https://pl.wikipedia.org/wiki/709\" target=\"_blank\" rel=\"noopener noreferrer\">709</a> roku.", "Wisław": "<b>Wisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone ze skróconego członu <i>Wit-</i> („pan, władca”), i <i>-sław</i> („sława”). Mogło ono mieć charakter życzący i oznaczać „tego, który będzie sławnym panem”. Formą pełniejszą tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Witos%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Witosław</a>.", "Witt": "<b>Witt</b> – <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> pochodzące od imion <a href=\"https://pl.wikipedia.org/wiki/Wit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wit</a> i <a href=\"https://pl.wikipedia.org/wiki/Witold_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Witold</a>, oznaczające \"witać\", \"pozdrawiać kogoś przy spotkaniu\", dawniej \"przybywać\". W roku <a href=\"https://pl.wikipedia.org/wiki/1994\" target=\"_blank\" rel=\"noopener noreferrer\">1994</a> w Polsce mieszkały 1772 osoby o tym nazwisku, najwięcej w dawnym <a href=\"https://pl.wikipedia.org/wiki/Wojew%C3%B3dztwo_pilskie\" target=\"_blank\" rel=\"noopener noreferrer\">województwie pilskim</a> (252).", "Wojbor": "<b>Wojbor</b> – imię <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> złożone z dwóch członów: woj - <i>wojownik</i> i bor - <i>walka</i>. Może to oznaczać: walka wojownika, wojownik waleczny itd.", "Wszebor": "<b>Wszebor</b>, <b>Wszabor</b>, <b>Wświebor</b>, <b>Świebor</b>, <b>Śwsiebor</b>, <b>Siebor</b>, <b>Siabor</b>, <b>Szabor</b>, <b>Szebor</b>, <b>Wszeborz</b>, <b>Świeborz</b>, <b>Śwsieborz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> (\"wszystek, każdy, zawsze\") w różnych wersjach nagłosowych, oraz członu <i>-bor</i> (\"walczyć, zmagać się\"). Mogło oznaczać \"ten, który zawsze podejmuje walkę\". Pisownia z końcowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>.", "Wagner": "<b>Wagner</b> – nazwisko to pochodzi od germańskiego słowa „Waganari” określającego <a href=\"https://pl.wikipedia.org/wiki/Wo%C5%BAnica\" target=\"_blank\" rel=\"noopener noreferrer\">woźnicę</a> lub budowniczego wozów (szczególnie wśród pensylwańskich Holendrów). Otrzymywały je osoby trudniące się zawodowo transportem szeroko pojętych dóbr, w zaprzęgniętych wozach lub furmankach z wysokimi burtami.", "Więcesław": "Pod wpływem języka czeskiego przyjęła się jego forma <a href=\"https://pl.wikipedia.org/wiki/Wac%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wacław</a>. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Wschodniosłowiańskim</a> odpowiednikiem tego imienia jest <i>Вячеслав</i> (Wiaczesław). Z kolei imię <a href=\"https://pl.wikipedia.org/wiki/Wie%C5%84czys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wieńczysław</a> mogło powstać w wyniku specyficznego odczytania imienia <i>Więcesław</i>.", "W": "<b>W</b> (wymowa: <i>wu</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>w</b>) – dwudziesta trzecia litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dwudziesta ósma litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. W języku polskim i niemieckim oznacza spółgłoskę [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">v</a>], a w angielskim – [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a>].", "Wyszomir": "<b>Wyszomir</b>, <i><b>Wyszymir</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Wysze-</i> (\"wyższy, ceniony ponad wszystko, stawiany ponad innymi\") i <i>-mir</i> (\"pokój\"). Może więc oznaczać \"ten, który ceni pokój ponad wszystko\".", "Witomir": "<b>Witomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>, nienotowane w źródłach staropolskich.", "Wergiliusz": "Wergiliusz pochodził z niezamożnej rodziny z <a href=\"https://pl.wikipedia.org/wiki/Galia_Przedalpejska\" target=\"_blank\" rel=\"noopener noreferrer\">Galii Cisalpejskiej</a>. W młodości znajdował się pod wpływem innych rzymskich poetów, co było widoczne w jego młodzieńczych <i>Drobiazgach</i>. Swój własny język, styl i sposób wyrazu odnalazł w <i>Bukolikach</i>, które przyniosły mu sławę i tytuł największego poety Rzymu. Na talencie Wergiliusza poznali się <a href=\"https://pl.wikipedia.org/wiki/Gajusz_Cilniusz_Mecenas\" target=\"_blank\" rel=\"noopener noreferrer\">Mecenas</a> i <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">August</a>, którzy obdarzyli go opieką, majątkiem i przyjaźnią. Po opublikowaniu <i>Georgik</i>, przyjętych od razu jako arcydzieło, na prośbę Augusta rozpoczął pisać <i>Eneidę</i>, <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">epopeję</a> poświęconą historii Rzymu. Śmierć uniemożliwiła mu dokończenie tego poematu.", "Włodzimir": "<b>Włodzimir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się ze słów <i>Włodzi-</i> – „panuje” i <i>-mir</i> – „pokój”.", "Wiktoria": "<b>Wiktoria</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>victoria</em> – „zwycięstwo”). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> nosiła je <a href=\"https://pl.wikipedia.org/wiki/Wiktoria_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> zwycięstwa i chwały.", "Wataru": "<b>Wataru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;わたる, ワタル, 渉) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone głównie przez mężczyzn, rzadko noszone przez kobiety.", "Wiktoriusz": "<b>Wiktor</b>, <b>Wiktoriusz</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>victor</em> – zwycięzca) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Waleriusz": "<b>Waleriusz</b> – imię męskie i oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Walery\" target=\"_blank\" rel=\"noopener noreferrer\">Walery</a>.", "Weronika": "<b>Weronika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego. Późniejsza forma imienia <a href=\"https://pl.wikipedia.org/wiki/Berenika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Berenike</a>. Etymologia imienia wywodzona jest z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> φέρω <i>phero</i> – \"niosę\" i νίκη <i>nike</i> – \"zwycięstwo\". Oznacza zatem <i>tę, która zwycięża</i>. W średniowieczu imię było błędnie przypisywane słowom <i>vera</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> – prawdziwa) i <i>eikon</i> (gr. – obraz). Nawiązywano w ten sposób do legendy o <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Weronika\" target=\"_blank\" rel=\"noopener noreferrer\">św. Weronice</a>, która otarła chustą twarz <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusowi</a>. Powstały w ten sposób na chuście wizerunek określany był jako prawdziwy wizerunek Chrystusa – Veraikon.", "Weibo": "Platforma została założona w 2009 roku. Według doniesień z 2014 roku z Sina Weibo korzystało wówczas miesięcznie ok. 130 mln użytkowników.W 2013 roku przychody korporacji Sina Weibo wyniosły 188 mln dolarów amerykańskich.", "Wenyan": "<i>Wenyan</i> jest oparty na języku starożytnej literatury chińskiej, głównie tekstów pochodzących z czasów <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Han\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii Han</a> (ten język określany jest po chińsku mianem 古文 gǔwén). Ze względu na ewolucję fonologii mówionego chińskiego, która doprowadziła do powstania ogromnej ilości <a href=\"https://pl.wikipedia.org/wiki/Homofonia_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">homofonów</a>, język klasyczny stopniowo stał się praktycznie niezrozumiały w formie mówionej, był jednak nadal używany w piśmie bez większych zmian.", "Winand": "<b>Winand</b>, Wignand – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>wig</i> – \"walka, wojna\", i <i>-nand</i> – \"dzielny, odważny\", które mogło oznaczać \"odważny wojownik\" (por. <a href=\"https://pl.wikipedia.org/wiki/Wigbert\" target=\"_blank\" rel=\"noopener noreferrer\">Wigbert</a>, <a href=\"https://pl.wikipedia.org/wiki/Ferdynand\" target=\"_blank\" rel=\"noopener noreferrer\">Ferdynand</a>).", "Wierzyn": "<b>Ekspedyt</b>, <b>Wierzyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <em>expediō, expedīre</em> („uwolnić, wyzwolić z więzów”), <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>expedītus</em> znaczy „uwolniony, lekko ubrany, lekkozbrojny; szybki, zwinny”. Imię to zostało w Polsce przetłumaczone jako <b>Wierzyn</b> („ten, któremu można wierzyć”). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Ekspedyt</a>.", "Władysława": "<b>Władysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>. Istnieje również bardzo rzadko występująca forma <i>Ładysława</i>, stanowiąca zapożyczenie z języków sąsiednich, zwł. czeskiego i słowackiego, a także forma <b><a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzisława</a></b> – nienotowana w dawnych źródłach, lecz stanowiąca odpowiednik staropolskiego imienia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzisław</a>, które pod wpływem języka czeskiego przybrało formę <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>.", "Winny": "Nazwa pochodzi od programu WinMX, w której litery \"M\" oraz \"X\" zastąpiono kolejnymi literami <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, czyli \"N\" oraz \"Y\". Według informacji podanych przez Tokyo-based Association of Copyright for Computer Software we wrześniu <a href=\"https://pl.wikipedia.org/wiki/2003\" target=\"_blank\" rel=\"noopener noreferrer\">2003</a> roku z aplikacji korzystało 250.000 użytkowników. Według serwisu P2Pnet, był to najbardziej popularny program do wymiany plików w <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>, wyprzedzający WinMX.", "Wynn": "<b>Ƿ</b>, <b>ƿ</b> (<b>Wynn</b>) <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu staroangielskiego</a> pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Runy\" target=\"_blank\" rel=\"noopener noreferrer\">pisma runicznego</a> <a href=\"https://pl.wikipedia.org/wiki/Fu%C3%BEork\" target=\"_blank\" rel=\"noopener noreferrer\">fuþork</a>. Zastępowała przed rokiem <a href=\"https://pl.wikipedia.org/wiki/1300\" target=\"_blank\" rel=\"noopener noreferrer\">1300</a> połączenie <i>uu</i>, z którego pochodzi <i>w</i>. Później była używana do druku tekstów staroangielskich, ale na początku <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> zastąpiono ją współczesną literą <a href=\"https://pl.wikipedia.org/wiki/W\" target=\"_blank\" rel=\"noopener noreferrer\">w</a> ze względu na podobny wygląd do <a href=\"https://pl.wikipedia.org/wiki/P\" target=\"_blank\" rel=\"noopener noreferrer\">p</a>.", "Wrocisław": "<b>Wrocisław</b>, <b>Wrocsław</b>, <b>Wrosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Wroci-</i> („wrócić, wrócić się, przywrócić”) i <i>-sław</i> („sława”). Może zatem oznaczać \"ten, który przywróci sławę\". Polska nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Wroc%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wrocław</a> pochodzi od jednej ze skróconych form tego imienia: Wrocisław → Wrocsław. Podobną etymologię ma nazwa stolicy <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>, <a href=\"https://pl.wikipedia.org/wiki/Bratys%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Bratysława</a>.", "Wiercisław": "<b>Wiercisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członów: <i>Wierci-</i> (\"wiercić\") i <i>-sław</i> (\"sława\").", "Wińczysław": "<b>Wieńczysław</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone w czasach nowszych; jego zapisy pojawiają się dopiero w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>. Prawdopodobnie powstało przez analogię do imion staropolskich i miało oznaczać „ten, którego wieńczy sława”. Inną hipotezą jest powstanie tego imienia w wyniku specyficznego odczytania imienia <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesław</a>, być może za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">języków wschodniosłowiańskich</a> (<b>Wiaczesław</b>).", "Władlen": "<b>Władlen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, skrót od <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimierz_Lenin\" target=\"_blank\" rel=\"noopener noreferrer\">Władimir Lenin</a>, powstałe jako <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> w <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zek_Socjalistycznych_Republik_Radzieckich\" target=\"_blank\" rel=\"noopener noreferrer\">Związku Radzieckim</a> po <a href=\"https://pl.wikipedia.org/wiki/Rewolucja_pa%C5%BAdziernikowa\" target=\"_blank\" rel=\"noopener noreferrer\">rewolucji październikowej</a>.", "Wunibald": "<b>Winibald</b>, <b>Wunibald</b>, <b>Winebald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>wunne-</i> (<i>wünne</i>, <i>wunni</i>, <i>wunne</i>) – „przyjaciel” i <i>-bald</i> – „mocny, odważny, zuchwały”. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Wunibald_z_Heidenheim\" target=\"_blank\" rel=\"noopener noreferrer\">Wunibald z Heidenheim</a> w <a href=\"https://pl.wikipedia.org/wiki/Bawaria\" target=\"_blank\" rel=\"noopener noreferrer\">Bawarii</a> (VIII wiek), brat <a href=\"https://pl.wikipedia.org/wiki/Willibald_z_Eichst%C3%A4tt\" target=\"_blank\" rel=\"noopener noreferrer\">św. Willibalda</a>. Forma <b>Winibald</b> jest późniejsza i bardziej rozpowszechniona w Polsce.", "Wigbert": "<b>Wigbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członow <i>wig</i> – „wojna” oraz <i>beraht</i> – „błyszczeć, jaśnieć” i oznaczające „sławny wojownik” (por. <a href=\"https://pl.wikipedia.org/wiki/Winand\" target=\"_blank\" rel=\"noopener noreferrer\">Winand</a>).", "Wyszemir": "<b>Wyszemir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Wysze-</i> („wyższy, ceniony ponad wszystko, stawiany ponad innymi”) i <i>-mir</i> („pokój”). Może więc oznaczać „ten, który ceni pokój ponad wszystko”.", "Wszemir": "<b>Wszemir</b>, <b>Wszemiar</b>, <b>Świemir</b>, <b>Siemir</b>, <b>Siemar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w różnych wersjach nagłosowych, oraz członu <i>-mir</i> („pokój, spokój, dobro”).", "Wanda": "<b>Wanda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wymyślone najprawdopodobniej przez <a href=\"https://pl.wikipedia.org/wiki/Wincenty_Kad%C5%82ubek\" target=\"_blank\" rel=\"noopener noreferrer\">Wincentego Kadłubka</a>, wcześniej nieznane. Według Kadłubka było to imię <a href=\"https://pl.wikipedia.org/wiki/Wanda_(legendarna_ksi%C4%99%C5%BCniczka)\" target=\"_blank\" rel=\"noopener noreferrer\">legendarnej władczyni</a> <a href=\"https://pl.wikipedia.org/wiki/Krak%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Krakowa</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Krak\" target=\"_blank\" rel=\"noopener noreferrer\">Kraka</a>. Początkowo, w XII–XIV w. zapisywane także „Węda”. Stało się popularne w XIX wieku, w związku z <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantyczną</a> modą na <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecze</a>.", "Wiesława": "<b>Wiesława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, zdrobniale: Wiesia, Wisia. Jest to żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wies%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wiesław</a>. Była to skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Wielis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wielisława</a>. Mogło oznaczać „tę, która pragnie sławy”.", "Wioletta": "<b>Wioleta</b>, <b>Wioletta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Włoska <i>Violetta</i>, której jest spolszczeniem, stanowi zdrobnienie wł. imienia <i>Viola</i>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „<a href=\"https://pl.wikipedia.org/wiki/Fio%C5%82ek\" target=\"_blank\" rel=\"noopener noreferrer\">fiołek</a>” (zob. też <a href=\"https://pl.wikipedia.org/wiki/Wiola\" target=\"_blank\" rel=\"noopener noreferrer\">Wiola</a>). W Polsce Wioletta należy do imion nowych, pojawiła się w XIX wieku, w polskiej literaturze po raz pierwszy w <i><a href=\"https://pl.wikipedia.org/wiki/Kordian_(dramat)\" target=\"_blank\" rel=\"noopener noreferrer\">Kordianie</a></i> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>. Imię to spotykane bywa w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> również w formie <i>Violetta</i>, jednakże forma ta ma negatywną opinię Rady Języka Polskiego.", "Wioleta": "<b>Wioleta</b>, <b>Wioletta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Włoska <i>Violetta</i>, której jest spolszczeniem, stanowi zdrobnienie wł. imienia <i>Viola</i>, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „<a href=\"https://pl.wikipedia.org/wiki/Fio%C5%82ek\" target=\"_blank\" rel=\"noopener noreferrer\">fiołek</a>” (zob. też <a href=\"https://pl.wikipedia.org/wiki/Wiola\" target=\"_blank\" rel=\"noopener noreferrer\">Wiola</a>). W Polsce Wioletta należy do imion nowych, pojawiła się w XIX wieku, w polskiej literaturze po raz pierwszy w <i><a href=\"https://pl.wikipedia.org/wiki/Kordian_(dramat)\" target=\"_blank\" rel=\"noopener noreferrer\">Kordianie</a></i> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>. Imię to spotykane bywa w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> również w formie <i>Violetta</i>, jednakże forma ta ma negatywną opinię Rady Języka Polskiego.", "Wacława": "<b>Wacława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wac%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wacław</a>. Forma Wacława jest <a href=\"https://pl.wikipedia.org/wiki/Czechizm\" target=\"_blank\" rel=\"noopener noreferrer\">czechizmem</a>. W źródłach polskich imię to poświadczone jest w staropolskiej formie <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> (1263 rok) i Więcsława (1314 rok).", "Walentyna": "<b>Walentyna</b> – imię pochodzenia łacińskiego, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Walenty\" target=\"_blank\" rel=\"noopener noreferrer\">Walenty</a>, <a href=\"https://pl.wikipedia.org/wiki/Walenty\" target=\"_blank\" rel=\"noopener noreferrer\">Walentyn</a>.", "Waleria": "<b>Waleria</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> ‘Valeria’, utworzone od nazwy rodu <i>Waleriuszy</i>; jest żeńskim odpowiednikiem imion <a href=\"https://pl.wikipedia.org/wiki/Walery\" target=\"_blank\" rel=\"noopener noreferrer\">Walery</a> i <a href=\"https://pl.wikipedia.org/wiki/Walerian\" target=\"_blank\" rel=\"noopener noreferrer\">Walerian</a>.", "Wanessa": "<b>Wanesa</b>, <b>Wanessa</b> – żeńskie imię pochodzenia literackiego, stworzone przez irlandzkiego pisarza <a href=\"https://pl.wikipedia.org/wiki/Jonathan_Swift\" target=\"_blank\" rel=\"noopener noreferrer\">Jonathana Swifta</a> od pierwszych sylab imienia i nazwiska jego przyjaciółki Esther Vanhomrigh. Nie ma męskiego odpowiednika. W Polsce imię zostało nadane po raz pierwszy w latach 60. XX wieku.", "Wanesa": "<b>Wanesa</b>, <b>Wanessa</b> – żeńskie imię pochodzenia literackiego, stworzone przez irlandzkiego pisarza <a href=\"https://pl.wikipedia.org/wiki/Jonathan_Swift\" target=\"_blank\" rel=\"noopener noreferrer\">Jonathana Swifta</a> od pierwszych sylab imienia i nazwiska jego przyjaciółki Esther Vanhomrigh. Nie ma męskiego odpowiednika. W Polsce imię zostało nadane po raz pierwszy w latach 60. XX wieku.", "Wilhelmina": "<b>Wilhelmina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wilhelm\" target=\"_blank\" rel=\"noopener noreferrer\">Wilhelm</a>. Patronką tego imienia jest św. Emilia Maria Wilhelmina de Rodat.", "Wincentyna": "<b>Wincentyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, jeden z żeńskich odpowiedników imienia <a href=\"https://pl.wikipedia.org/wiki/Wincenty\" target=\"_blank\" rel=\"noopener noreferrer\">Wincenty</a> (łac. <i>vincens</i> – zwyciężający).", "Wera": "<b>Wera</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, stanowiące żeńską formę łacińskiego imienia Werus (pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a>), równe wyrazowi pospolitemu <i>vera</i> — \"rzetelna, prawa, słuszna, sprawiedliwa\". Forma ta jest również w użyciu jako zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Weronika\" target=\"_blank\" rel=\"noopener noreferrer\">Weronika</a> lub zachodnia transliteracja rosyjskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Wiara_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiera</a>. Rozpowszechniła się ona być może pod wpływem działaczki socjalistycznej i komunistycznej <a href=\"https://pl.wikipedia.org/wiki/Maria_Koszutska\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Koszutskiej</a>, która przybrała pseudonim Wera Kostrzewa.", "Waltrauda": "<b>Waldetruda</b>, <b>Waltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało ono ze staro-wysoko-niemieckich słów <i>waltan</i> – \"panować, rządzić\" lub <i>walh</i> – 'cudzoziemiec' oraz <i>trud</i> – 'siła, potęga' i w związku z tym oznacza \"silna, potężna władczyni\" lub \"silna, potężna cudzoziemka\". Patronką imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Waldetruda_(ksieni_z_Mons)\" target=\"_blank\" rel=\"noopener noreferrer\">Waldetruda (ksieni z Mons)</a>.", "Walburga": "<b>Walburga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako złożenie członów <i>waldan</i> – „rządzić, panować” i <i>burg</i> – „gromadzić, strzec, pilnować, ochraniać”. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Walburga_(%C5%9Bwi%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Walburga</a>, zakonnica, zm. w <a href=\"https://pl.wikipedia.org/wiki/779\" target=\"_blank\" rel=\"noopener noreferrer\">779</a> roku. Imię to zapisywano również w formie <b>Walpurga</b>, stąd <a href=\"https://pl.wikipedia.org/wiki/Noc_Walpurgi\" target=\"_blank\" rel=\"noopener noreferrer\">noc Walpurgi</a>.", "Wielisława": "<b>Wielisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się z członów: <i>Wiele-</i> („chcieć, kazać, radzić”) i <i>-sława</i> („sława”). Mogło oznaczać „tę, która pragnie sławy”. Skróconą formą tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Wies%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wiesława</a>. W źródłach poświadczone od 1405 roku.", "Wisława": "<b>Wisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> żeńskie, będące skróconą formą imienia <a href=\"https://pl.wikipedia.org/wiki/Witos%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Witosława</a> albo <a href=\"https://pl.wikipedia.org/wiki/Wojs%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wojsława</a>. Poświadczone od <a href=\"https://pl.wikipedia.org/wiki/1273\" target=\"_blank\" rel=\"noopener noreferrer\">1273</a> roku jako <i>Wisława</i> ||<i>Wysława</i>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wisław</a>.", "Wieńczysława": "<b>Wieńczysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wie%C5%84czys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wieńczysław</a>, utworzonego w nowszych czasach na wzór imion staropolskich.", "Wiwiana": "<b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Wiola": "<b>Wiola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego (<a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>íon</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac</a>. <i>viola</i> - \"fiołek\") używane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> już w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Z historycznego punktu widzenia imię <a href=\"https://pl.wikipedia.org/wiki/Wioleta\" target=\"_blank\" rel=\"noopener noreferrer\">Wioleta</a> stanowi zdrobnienie od <b>Wioli</b>. Imię z pisownią przez \"<a href=\"https://pl.wikipedia.org/wiki/V\" target=\"_blank\" rel=\"noopener noreferrer\">V</a>\" otrzymało negatywną opinię <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rady Języka Polskiego</a>.", "Wilma": "<b>Wilhelmina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wilhelm\" target=\"_blank\" rel=\"noopener noreferrer\">Wilhelm</a>. Patronką tego imienia jest św. Emilia Maria Wilhelmina de Rodat.", "Wita": "<b>Beta</b> (<b>wita</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βῆτα, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>βήτα</b>, pisana <b>Ββ</b> lub <b>ϐ</b>) – druga <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznaczała liczbę <a href=\"https://pl.wikipedia.org/wiki/2_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">2</a>. Beta pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> bet <a href=\"https://pl.wikipedia.org/wiki/Plik:Phoenician_beth.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Od bety pochodzą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/B\" target=\"_blank\" rel=\"noopener noreferrer\">B</a> i <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylickie</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%91\" target=\"_blank\" rel=\"noopener noreferrer\">Б</a> i <a href=\"https://pl.wikipedia.org/wiki/%D0%92\" target=\"_blank\" rel=\"noopener noreferrer\">В</a>.", "Witosława": "<b>Witosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Wit(o)-</i> („pan, władca”), i <i>-sława</i> („sława”). Zanotowane zostało po raz pierwszy w 1265 r. Mogło ono mieć charakter życzący i oznaczać „tę, która będzie sławną panią”. Formą skróconą tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wisława</a>, a męskimi odpowiednikami – odpowiednio <a href=\"https://pl.wikipedia.org/wiki/Witos%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Witosław</a> i <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wisław</a>.", "Witolda": "<b>Witolda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Witold_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Witold</a> o znaczeniu „władająca ludem”.", "Wiwianna": "<b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Włodzisława": "<b>Włodzisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a> imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzisław</a>, złożonego z członów <i>Włodzi-</i> („władać, panować”) i <i>-sław</i>, z którego w późniejszym czasie pod wpływem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">języka czeskiego</a> powstała bardziej znana forma – <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a> (i jego żeński odpowiednik – <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Władysława</a>).", "Waleriana": "<b>Waleriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Walerian\" target=\"_blank\" rel=\"noopener noreferrer\">Walerian</a>, oznaczające „należąca do Waleriusza, pochodząca od Waleriusza”.", "Więcesława": "<b>Więcesława</b>, <b>Więcsława</b>, <b>Więcława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Więce-</i> (\"więcej\") i <i>-sława</i> (\"sława\"). Znaczenie imienia: \"ta, która ma więcej sławy\". Pod wpływem języka czeskiego przyjęła się jego forma <a href=\"https://pl.wikipedia.org/wiki/Wac%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wacława</a>. Z kolei imię <a href=\"https://pl.wikipedia.org/wiki/Wie%C5%84czys%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wieńczysława</a> mogło powstać w wyniku błędnego odczytania imienia <i><b>Więcesława</b></i>. Żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesław</a>.", "Witalia": "<b>Witalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Witalis\" target=\"_blank\" rel=\"noopener noreferrer\">Witalis</a>. Wywodzi się od słowa oznaczającego „życiowa, zdolna do życia” (<i>vitalis</i>). Równoważnikiem znaczeniowym tego imienia jest imię <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Żywia</a>.", "Wiktoryna": "<b>Wiktoryna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryn</a> o pochodzeniu łacińskim.", "Wojciecha": "<b>Wojciecha</b>, <b>Wociecha</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się z członów oznaczających „ta, która cieszy jako żołnierz” czyli „wojownik pociecha”, „ta, której walka sprawia radość”. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Wojciech\" target=\"_blank\" rel=\"noopener noreferrer\">Wojciech</a>.", "Wiara": "<b>Wiara</b>, Wiera – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od nazwy jednej z cnót chrześcijańskich – <a href=\"https://pl.wikipedia.org/wiki/Wiara_(chrze%C5%9Bcija%C5%84stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">wiary</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>fides</em>). Popularną zachodnioeuropejską transliteracją tego imienia jest <i>Vera</i>, a jego odpowiednikiem w krajach wschodniosłowiańskich – <i>Wiera</i>.", "Włodzimira": "<b>Włodzimira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się ze słów <i>Włodzi-</i> – „panuje” i <i>-mira</i> – „pokój”. Na skutek zniekształcenia, jakiemu uległ męski odpowiednik tego imienia, <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimir\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzimir</a>, pod wpływem imion niemieckich przekształcony w formę <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimierz\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzimierz</a>, imię <b>Włodzimira</b> może również przybierać formę <b>Włodzimiera</b>.", "Wala": "<b>Wala</b> (<i>pełna nazwa</i> <b>Wala Heilmittel GmbH</b>) - to założona przez <a href=\"https://pl.wikipedia.org/wiki/Rudolf_Hauschka\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolfa Hauschka</a> w <a href=\"https://pl.wikipedia.org/wiki/1935\" target=\"_blank\" rel=\"noopener noreferrer\">1935</a> roku firma, produkująca kosmetyki (około 100 różnych produktów) oraz maści (około 1000 różnych produktów). Nazwa Wala jest skrótem od Wärme – Asche, Licht – Asche, co oznacza: Ciepło - popiół, światło - popiół. Leki są wytwarzane zgodnie z zasadami <a href=\"https://pl.wikipedia.org/wiki/Antropozofia\" target=\"_blank\" rel=\"noopener noreferrer\">antropozofii</a>.", "Wenancja": "<b>Wenancja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>venans</i> – \"polujący\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Wenancjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Wenancjusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Wenanty\" target=\"_blank\" rel=\"noopener noreferrer\">Wenanty</a>.", "Wiki": "Nazwa wiki pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hawajski\" target=\"_blank\" rel=\"noopener noreferrer\">hawajskiego</a> wyrażenia „wiki wiki”, oznaczającego „bardzo szybko”. Autorem pojęcia i koncepcji jest <a href=\"https://pl.wikipedia.org/wiki/Ward_Cunningham\" target=\"_blank\" rel=\"noopener noreferrer\">Ward Cunningham</a>, który w 1994 roku na potrzeby <a href=\"https://pl.wikipedia.org/wiki/Portland_Pattern_Repository\" target=\"_blank\" rel=\"noopener noreferrer\">Portland Pattern Repository</a> napisał oprogramowanie <a href=\"https://pl.wikipedia.org/wiki/WikiWikiWeb\" target=\"_blank\" rel=\"noopener noreferrer\">WikiWikiWeb</a>.", "Włada": "<b>Włada</b> – polskie imię żeńskie pochodzące od imienia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Władysława</a>. Włada imieniny obchodzi <a href=\"https://pl.wikipedia.org/wiki/12_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">12 czerwca</a>, <a href=\"https://pl.wikipedia.org/wiki/30_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">30 czerwca</a> i <a href=\"https://pl.wikipedia.org/wiki/25_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 września</a>. Męskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>.", "Wszemiła": "<b>Wszemiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Wsze-</i> (\"wszystek, każdy, zawsze\") w różnych wersjach nagłosowych, oraz członu <i>-miła</i> (\"miła\"). Znaczenie imienia: \"wszystkim miła\", \"lubiana przez wszystkich\".", "Wirgilia": "<b>Wirgilia</b>, <b>Wergilia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Imię pochodzi od rzymskiego rodu <i>Wirgiliuszów</i>, <i>Wergiliuszów</i>. Wśród patronów tego imienia znajduje się <a href=\"https://pl.wikipedia.org/wiki/Wirgiliusz_z_Arles\" target=\"_blank\" rel=\"noopener noreferrer\">św. Wirgiliusz z Arles</a>, który <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/5_marca\" target=\"_blank\" rel=\"noopener noreferrer\">5 marca</a>.", "Weridiana": "<b>Wirydiana</b>, <b>Wirydianna</b> lub <b>Weridiana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od przymiotnika <i>viridis</i> – \"zielony, młodzieńczy, świeży\". Patronka tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Weridiana_z_Castelfiorentino\" target=\"_blank\" rel=\"noopener noreferrer\">św. Wirydiana</a>, dziewica, zyskała jeszcze za swojego życia wielką sławę i była nawet odwiedzana przez <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>.", "Westyna": "<b>Westyna</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające <i>kobieta z ludu Westynów</i> (antycznego ludu zamieszkującego dzisiejszą <a href=\"https://pl.wikipedia.org/wiki/Abruzja\" target=\"_blank\" rel=\"noopener noreferrer\">Abruzję</a>). Jego patronką jest św. Westyna, wspominana razem ze św. Donatą, Januarią, Sekundą i innymi świętymi.", "Werena": "<b>Werena</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, prawdopodobnie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>verus</i> - \"prawdziwy\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Werena_z_Zurzach\" target=\"_blank\" rel=\"noopener noreferrer\">św. Werena</a>, pielęgniarka, z <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>.", "Weselina": "<b>Weselina</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a>&#160;Веселина) – <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskie</a> żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a>, pochodzące od imienia <a href=\"https://pl.wikipedia.org/wiki/Bazyli\" target=\"_blank\" rel=\"noopener noreferrer\">Wasyl</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułg.</a>&#160;Васил, Wasił), męska forma to Weselin.", "Wojsława": "<b>Wojsława</b>, <b>Wojesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Woj-</i> (\"wojownik\") i <i>-sława</i> (\"sława\"). Oznacza „tę, która zdobywa sławę w wojnach”, „sławną wojowniczkę”. Imię to mogło być skracane również do formy <a href=\"https://pl.wikipedia.org/wiki/Wis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wisława</a>. Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Wojs%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wojsław</a>.", "Wincencja": "<b>Wincencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, jeden z żeńskich odpowiedników męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Wincenty\" target=\"_blank\" rel=\"noopener noreferrer\">Wincenty</a> (łac. <i>vincens</i> - zwyciężający). Nowe Martyrologium Rzymskie wspomina dwie święte tego imienia.", "Wiwian": "<b>Bibian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające \"należący do rodu <i>Vivii</i>\". Patronem tego imienia jest św. Bibian, biskup <a href=\"https://pl.wikipedia.org/wiki/Saintes\" target=\"_blank\" rel=\"noopener noreferrer\">Saintes</a> (<a href=\"https://pl.wikipedia.org/wiki/V_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">V wiek</a>).", "Westa": "<b>Westa</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Vesta</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> bogini ogniska domowego i państwowego, odpowiednik bogini <a href=\"https://pl.wikipedia.org/wiki/Hestia\" target=\"_blank\" rel=\"noopener noreferrer\">Hestii</a> w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>.", "Wakako": "<b>Wakako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;わかこ, ワカコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Wiesia": "<b>Wiesława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, zdrobniale: Wiesia, Wisia. Jest to żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Wies%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wiesław</a>. Była to skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Wielis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Wielisława</a>. Mogło oznaczać „tę, która pragnie sławy”.", "Wakana": "<b>Wakana</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;わかな, ワカナ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Włościsława": "<b>Włościsława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się z członów: <i>Włości-</i> („panować”) i <i>-sława</i> („sława”). Oznacza „tę, która panuje nad swoją sławą”.", "Wiwina": "<b>Wiwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od łacińskiego nazwiska <i>Vivius</i> i oznaczające „córkę Viviusa”. Patronką tego imienia jest św. Wiwina (zm. w <a href=\"https://pl.wikipedia.org/wiki/1170\" target=\"_blank\" rel=\"noopener noreferrer\">1170</a> roku).", "Wenefryda": "<b>Wenefryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia celtyckiego, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a> <i>Gwenfrewi</i>: <i>gwen</i> to \"biały, prawy, błogosławiony\", a <i>frewi</i> - \"pojednianie, zgoda, pokój\". Inny wariant tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Ginewra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ginewra</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Wenefryda\" target=\"_blank\" rel=\"noopener noreferrer\">św. Wenefryda</a> z <a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">Walii</a> (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>). Inne formy to <i>Wenfryda</i>, <i>Wenfreda</i>, <i>Winifreda</i>, <i>Wenifreda</i>, <i>Winfryda</i>, <i>Winfreda</i>, <i>Winifred</i>, <i>Winfried</i> i <i>Winfrida.</i>", "Winanda": "<b>Winanda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Winand\" target=\"_blank\" rel=\"noopener noreferrer\">Winand</a>, Wignand, złożonego z członów <i>wig</i> — \"walka, wojna\", i <i>-nand</i> — \"dzielny, odważny\", które mogło oznaczać \"odważny wojownik\". Patronem tego imienia jest św. Winand, ksiądz z <a href=\"https://pl.wikipedia.org/wiki/Maastricht\" target=\"_blank\" rel=\"noopener noreferrer\">Maastricht</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/1233\" target=\"_blank\" rel=\"noopener noreferrer\">1233</a> roku.", "Wierzchosława": "<b>Wirzchosława</b>, <i><b>Wierzchosława</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie (notowane tylko w formie Wirzchosława). Składa się z członu <i>Wirzcho-</i> („wierzch, szczyt, czubek”) i <i>-sława</i> („sława”). Może oznaczać „znajdująca się u szczytu sławy”. Męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Wirzchos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Wirzchosław</a>.", "Wilda": "<b>Wilda</b> – część miasta <a href=\"https://pl.wikipedia.org/wiki/Pozna%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">Poznania</a> i jednocześnie jednostka obszarowa <a href=\"https://pl.wikipedia.org/wiki/System_Informacji_Miejskiej_w_Poznaniu\" target=\"_blank\" rel=\"noopener noreferrer\">Systemu Informacji Miejskiej (SIM)</a>, wchodząca w skład <a href=\"https://pl.wikipedia.org/wiki/Osiedle_Wilda\" target=\"_blank\" rel=\"noopener noreferrer\">osiedla administracyjnego Wilda</a>, leżąca w centralnej części miasta.", "Wanhua": "Populacja dzielnicy Wanhua w 2016 roku liczyła 193&#160;539 mieszkańców – 98&#160;327 kobiet i 95&#160;212 mężczyzn. Liczba gospodarstw domowych wynosiła 78&#160;551, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,46 osób."};
